import 'package:flutter_bloc/flutter_bloc.dart';import '../../Data/Repos/home_repo.dart';import 'news_books_state.dart';class NewsBooksCubit extends Cubit<NewsBooksState> {  NewsBooksCubit(this.homeRepo) : super(NewsBooksInitial());  static BlocProvider get(context) => NewsBooksCubit.get(context);  final HomeRepo homeRepo;  Future<void> fetchNewsBooksBooks() async {    emit(NewsBooksLoading());    await homeRepo.fetchNewsBooksOfComputerScience().then((value) {      value.fold((failure) => emit(NewsBooksFailure(error: failure.errMessage)),          (books) => emit(NewsBooksSuccess(books: books)));    });  }}